// Parse GlitchTip webhook format
const body = $input.first().json.body || $input.first().json;

const attachment = (body.attachments || [])[0] || {};
const fields = (attachment.fields || []);

// Extract fields by title
const getField = (name) => {
  const f = fields.find(f => f.title === name);
  return f ? f.value : '';
};

const title = attachment.title || body.text || 'Unknown Error';
const link = attachment.title_link || '';
const culprit = attachment.text || '';
const level = getField('Level') || 'error';
const project = getField('Project') || 'unknown';
const timesSeen = parseInt(getField('Times Seen') || '1', 10);
const firstSeen = getField('First Seen') || new Date().toISOString();
const lastSeen = getField('Last Seen') || new Date().toISOString();

// Create fingerprint from title for dedup
let hash = 0;
for (let i = 0; i < title.length; i++) {
  const char = title.charCodeAt(i);
  hash = ((hash << 5) - hash) + char;
  hash |= 0;
}
const fingerprint = Math.abs(hash).toString(16).padStart(8, '0');

const severity = ['fatal', 'critical'].includes(level.toLowerCase()) ? 'critical' :
                 level.toLowerCase() === 'warning' ? 'warning' : 'error';

return [{
  json: {
    title,
    link,
    culprit,
    level,
    severity,
    project,
    timesSeen,
    firstSeen,
    lastSeen,
    fingerprint,
    timestamp: new Date().toISOString()
  }
}];

// Rate limiter: max 10 issues per 5 minutes
const now = Date.now();
const WINDOW_MS = 5 * 60 * 1000;
const MAX_PER_WINDOW = 10;

const staticData = $getWorkflowStaticData('global');
if (!staticData.rateLimitLog) staticData.rateLimitLog = [];

// Clean old entries
staticData.rateLimitLog = staticData.rateLimitLog.filter(t => now - t < WINDOW_MS);

const count = staticData.rateLimitLog.length;
const rateLimited = count >= MAX_PER_WINDOW;

if (!rateLimited) {
  staticData.rateLimitLog.push(now);
}

return [{
  json: {
    ...$input.first().json,
    rateLimited,
    rateCount: count,
    rateWindow: '5min',
    rateMax: MAX_PER_WINDOW
  }
}];

const response = $input.first().json;
const body = response.body || response;
const items = body.items || [];
const totalCount = body.total_count || 0;

const prevData = $('Parse & Fingerprint').first().json;

return [{
  json: {
    ...prevData,
    hasDuplicate: totalCount > 0,
    existingIssueNumber: totalCount > 0 ? items[0].number : null,
    existingIssueUrl: totalCount > 0 ? items[0].html_url : null,
    duplicateCount: totalCount
  }
}];

