const milestones = $input.first().json.body || $input.first().json;
const prevData = $('Dedup Decision').first().json;

// Calculate current ISO week milestone title
const now = new Date();
const jan4 = new Date(now.getFullYear(), 0, 4);
const dayOfYear = Math.floor((now - new Date(now.getFullYear(), 0, 1)) / 86400000) + 1;
const weekNum = Math.ceil((dayOfYear + jan4.getDay()) / 7);
const title = `Week ${now.getFullYear()}-W${String(weekNum).padStart(2, '0')}`;

const match = (Array.isArray(milestones) ? milestones : []).find(m => m.title === title);

return [{
  json: {
    ...prevData,
    milestoneNumber: match ? match.number : null,
    milestoneTitle: match ? match.title : title,
    hasMilestone: !!match
  }
}];
